INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (0, "", 320, "", 0, 23001, 10, 2, 0, 20, 20001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, "リリ", 321, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 125801, 24001, 1, 2, 0, 1, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, "クリア", 322, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 126001, 24001, 2, 2, 0, 1, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, "プレシア", 323, "んーと。\nこれ、あげる。\nはい", 126101, 24001, 3, 2, 0, 1, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, "リリ", 324, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 125801, 24001, 4, 2, 0, 1, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, "クリア", 325, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 126001, 24001, 5, 2, 0, 1, 40011);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, "プレシア", 326, "お兄。\nきてくれて、うれしい", 126101, 24001, 6, 2, 0, 1, 40011);
